import{_ as a,o as t,c as o,a2 as s}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 20 — Replace","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/20-replace.md","filePath":"chapters/20-replace.md"}'),n={name:"chapters/20-replace.md"};function r(c,e,l,d,i,p){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="chapter-20-—-replace" tabindex="-1">Chapter 20 — Replace <a class="header-anchor" href="#chapter-20-—-replace" aria-label="Permalink to &quot;Chapter 20 — Replace&quot;">​</a></h1><blockquote><p><em>&quot;Replace is delete&#39;s surgical cousin—precise, targeted, and fast.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Vim offers several ways to replace text, from single characters to patterns across the entire file.</p><hr><h1 id="character-replacement" tabindex="-1">Character Replacement <a class="header-anchor" href="#character-replacement" aria-label="Permalink to &quot;Character Replacement&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>r</code></td><td>Replace <strong>one character</strong> under cursor</td></tr><tr><td><code>R</code></td><td>Enter <strong>Replace mode</strong> (overwrite text)</td></tr></tbody></table><h2 id="r-—-single-character-replace" tabindex="-1"><code>r</code> — Single Character Replace <a class="header-anchor" href="#r-—-single-character-replace" aria-label="Permalink to &quot;`r` — Single Character Replace&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>\n<span class="line"><span>^ cursor on H</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Press r then J:</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Jello World</span></span></code></pre></div><p>The cursor stays in normal mode after <code>r</code>.</p><h2 id="r-—-replace-mode" tabindex="-1"><code>R</code> — Replace Mode <a class="header-anchor" href="#r-—-replace-mode" aria-label="Permalink to &quot;`R` — Replace Mode&quot;">​</a></h2><p>Press <code>R</code> to enter Replace mode.</p><p>Every character you type overwrites the existing character under the cursor.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>\n<span class="line"><span>^</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Press R, type &quot;XYZ&quot;:</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>XYLo World</span></span></code></pre></div><p>Press <strong>Escape</strong> to exit Replace mode.</p><hr><h1 id="substitution-s" tabindex="-1">Substitution (<code>:s</code>) <a class="header-anchor" href="#substitution-s" aria-label="Permalink to &quot;Substitution (`:s`)&quot;">​</a></h1><p>The <code>:s</code> command substitutes text patterns.</p><p>Basic syntax:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:s/old/new/</span></span></code></pre></div><p>Replaces the first occurrence of <code>old</code> with <code>new</code> on the current line.</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:s/old/new/</code></td><td>Replace first <code>old</code> on current line</td></tr><tr><td><code>:s/old/new/g</code></td><td>Replace <strong>all</strong> <code>old</code> on current line</td></tr><tr><td><code>:%s/old/new/g</code></td><td>Replace all <code>old</code> in <strong>entire file</strong></td></tr><tr><td><code>:%s/old/new/gc</code></td><td>Replace all with <strong>confirmation</strong></td></tr><tr><td><code>:5,10s/old/new/g</code></td><td>Replace in lines 5–10</td></tr></tbody></table><h2 id="the-g-flag" tabindex="-1">The <code>g</code> Flag <a class="header-anchor" href="#the-g-flag" aria-label="Permalink to &quot;The `g` Flag&quot;">​</a></h2><p>Without <code>g</code>: only the first match per line.</p><p>With <code>g</code>: all matches per line.</p><h2 id="the-c-flag-—-confirmation" tabindex="-1">The <code>c</code> Flag — Confirmation <a class="header-anchor" href="#the-c-flag-—-confirmation" aria-label="Permalink to &quot;The `c` Flag — Confirmation&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:%s/old/new/gc</span></span></code></pre></div><p>Vim asks for confirmation at each match:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Replace with new? (y/n/a/q/l/^E/^Y)</span></span></code></pre></div><ul><li><code>y</code> — Yes</li><li><code>n</code> — No</li><li><code>a</code> — All (no more prompts)</li><li><code>q</code> — Quit</li><li><code>l</code> — Last (replace and stop)</li></ul><hr><h1 id="complex-replacements" tabindex="-1">Complex Replacements <a class="header-anchor" href="#complex-replacements" aria-label="Permalink to &quot;Complex Replacements&quot;">​</a></h1><h2 id="word-boundaries" tabindex="-1">Word Boundaries <a class="header-anchor" href="#word-boundaries" aria-label="Permalink to &quot;Word Boundaries&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:%s/\\&lt;old\\&gt;/new/g</span></span></code></pre></div><p>Only replaces <code>old</code> as a whole word (not <code>older</code>, <code>bold</code>).</p><h2 id="case-insensitive" tabindex="-1">Case Insensitive <a class="header-anchor" href="#case-insensitive" aria-label="Permalink to &quot;Case Insensitive&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:%s/old/new/gi</span></span></code></pre></div><h2 id="using-captures" tabindex="-1">Using Captures <a class="header-anchor" href="#using-captures" aria-label="Permalink to &quot;Using Captures&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:%s/\\(hello\\) world/\\1 there/g</span></span></code></pre></div><p>Replaces <code>hello world</code> with <code>hello there</code>.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key / Command</th><th>Action</th></tr></thead><tbody><tr><td><code>r</code></td><td>Replace one character</td></tr><tr><td><code>R</code></td><td>Replace mode</td></tr><tr><td><code>:s/old/new/</code></td><td>Replace first on line</td></tr><tr><td><code>:s/old/new/g</code></td><td>Replace all on line</td></tr><tr><td><code>:%s/old/new/g</code></td><td>Replace all in file</td></tr><tr><td><code>:%s/old/new/gc</code></td><td>Replace with confirmation</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>r{x}</code> replaces the character under cursor with <code>x</code>.</li><li><code>R</code> enters replace mode (overwrite as you type).</li><li><code>:s</code> is the substitution command.</li><li>Add <code>g</code> to replace all occurrences on a line.</li><li>Add <code>c</code> for confirmation prompts.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file and replace a single character with <code>r</code>.</li><li>Use <code>R</code> to overwrite several characters.</li><li>Replace all occurrences of a word in a file with <code>:%s/word/replacement/g</code>.</li><li>Practice with the confirmation flag <code>c</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./21-repeat.html"><strong>Chapter 21 — Repeat (.)</strong></a></p><p>Master the dot command — Vim&#39;s most powerful repetition tool.</p>',56)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
